switch($act){
  case 'detail':
    $id=isset($_POST['id'])?(int)$_POST['id']:0;$po=$db->fetch("SELECT * FROM production_order WHERE id_production_order=? LIMIT 1",array($id));if(!$po){echo '<div class="alert alert-warning">Production Order tidak ditemukan.</div>';break;}
