    foreach($grs as $g)echo '<tr><td>'.wipa_h($g->gr_no).'<br><small>'.wipa_h($g->confirmation_no).'</small></td><td>'.wipa_h($g->posting_date).'</td><td class="text-right">'.wipa_num($g->total_qty).'</td><td>'.wipa_h($g->status).'</td></tr>';
    echo '</tbody></table></div></div>';break;
  case 'excel':
    $initial=ob_get_level();ob_start();require_once "../../inc/lib/PHPExcel.php";require_once "../../inc/excel_style_helper.php";PHPExcel_Shared_File::setUseUploadTempDirectory(true);$from=isset($_GET['tgl_awal'])?$_GET['tgl_awal']:date('Y-m-01');$to=isset($_GET['tgl_akhir'])?$_GET['tgl_akhir']:date('Y-m-d');$status=isset($_GET['status'])?trim($_GET['status']):'';$plant=isset($_GET['plant'])?trim($_GET['plant']):'';$p=array($from,$to);$w=" WHERE p.status IN ('RELEASED','IN_PROCESS','CONFIRMED','TECO') AND p.start_date BETWEEN ? AND ? ";if($status!==''){$w.=" AND p.status=? ";$p[]=$status;}if($plant!==''){$w.=" AND p.plant=? ";$p[]=$plant;}
    $rows=$db->query("SELECT p.*,COALESCE(mat.required_qty,0) required_qty,COALESCE(mat.issued_qty,0) issued_qty,COALESCE(conf.yield_qty,0) yield_qty,COALESCE(conf.scrap_qty,0) scrap_qty,COALESCE(gr.gr_qty,0) gr_qty FROM production_order p LEFT JOIN(SELECT id_production_order,SUM(required_qty) required_qty,SUM(issued_qty) issued_qty FROM production_order_material GROUP BY id_production_order) mat ON mat.id_production_order=p.id_production_order LEFT JOIN(SELECT id_production_order,SUM(CASE WHEN status='POSTED' THEN yield_qty ELSE 0 END) yield_qty,SUM(CASE WHEN status='POSTED' THEN scrap_qty ELSE 0 END) scrap_qty FROM production_order_confirmation GROUP BY id_production_order) conf ON conf.id_production_order=p.id_production_order LEFT JOIN(SELECT h.id_production_order,SUM(CASE WHEN h.status='POSTED' THEN d.qty ELSE 0 END) gr_qty FROM erp_gr_production h JOIN erp_gr_production_detail d ON d.gr_id=h.id GROUP BY h.id_production_order) gr ON gr.id_production_order=p.id_production_order $w ORDER BY p.start_date,p.id_production_order",$p);
    $excel=new PHPExcel();$sh=$excel->setActiveSheetIndex(0);$sh->setTitle(erp_export_sheet_title('WIP Monitoring'));$heads=array(erp_export_label("No"),erp_export_label("Production Order"),erp_export_label("Status"),erp_export_label("Plant"),erp_export_label("Material"),erp_export_label("Order Qty"),erp_export_label("UOM"),erp_export_label("Start"),erp_export_label("Finish"),erp_export_label("Issued Material"),erp_export_label("Yield"),erp_export_label("GR Qty"),erp_export_label("Outstanding Confirmation"),erp_export_label("Outstanding GR"),erp_export_label("Scrap"),erp_export_label("Issue %"),erp_export_label("Confirm %"),erp_export_label("GR %"));foreach($heads as $i=>$v)$sh->setCellValue(PHPExcel_Cell::stringFromColumnIndex($i).'4',$v);$r=5;$n=1;foreach($rows as $row){$outConf=max((float)$row->order_qty-(float)$row->yield_qty,0);$outGr=max((float)$row->yield_qty-(float)$row->gr_qty,0);$vals=array($n++,$row->no_production_order,$row->status,$row->plant,$row->material_code.' - '.$row->material_name,(float)$row->order_qty,$row->uom,$row->start_date,$row->finish_date,(float)$row->issued_qty,(float)$row->yield_qty,(float)$row->gr_qty,$outConf,$outGr,(float)$row->scrap_qty,wipa_pct($row->issued_qty,$row->required_qty),wipa_pct($row->yield_qty,$row->order_qty),wipa_pct($row->gr_qty,$row->order_qty));foreach($vals as $i=>$v)$sh->setCellValue(PHPExcel_Cell::stringFromColumnIndex($i).$r,$v);$r++;}
    erpkb_excel_apply_standard_style($excel,array('sheet'=>$sh,'title'=>erp_export_title('WIP MONITORING'),'header_row'=>4,'first_data_row'=>5,'last_data_row'=>max(5,$r-1),'column_count'=>18,'numeric_columns'=>array('F','J','K','L','M','N','O'),'decimal_columns'=>array('P','Q','R'),'filters'=>array('Start Date'=>$from.' s/d '.$to,'Status'=>$status?:erp_export_all_text(),'Plant'=>$plant?:erp_export_all_text())));$tmp=erpkb_excel_temp_file('wip_monitoring_');PHPExcel_IOFactory::createWriter($excel,'Excel2007')->save($tmp);$size=@filesize($tmp);$sig=@file_get_contents($tmp,false,null,0,2);if(!$size||$sig!=='PK'){@unlink($tmp);while(ob_get_level()>$initial)ob_end_clean();header('Content-Type:text/plain; charset=utf-8');echo erp_t('export_excel_invalid_file','File Excel gagal dibuat dengan benar.');exit;}while(ob_get_level()>$initial)ob_end_clean();header('Content-Type: application/vnd.openxmlformats-officedocument.spreadsheetml.sheet');header('Content-Disposition: attachment; filename="wip_monitoring_'.date('Ymd_His').'.xlsx"');header('Content-Length: '.$size);header('Cache-Control: max-age=0');header('Pragma: public');readfile($tmp);@unlink($tmp);exit;
